module bin_to_gray(
    input [3:0] inverse_binary,
    output reg [3:0] gray
);

always @(*) begin
    gray[3] = inverse_binary[3];
    gray[2] = inverse_binary[3] ^ inverse_binary[2];
    gray[1] = inverse_binary[2] ^ inverse_binary[1];
    gray[0] = inverse_binary[1] ^ inverse_binary[0];
end

endmodule
